sql:
SELECT AVG(calories) AS average_calories
FROM desserts
WHERE status = 'Active';

SELECT AVG(calories) AS average_calories_per_active_dessert
FROM desserts
WHERE status = 'Active';

SELECT name
FROM desserts
WHERE status = 'Active';

SELECT AVG(calories) AS average_calories
FROM desserts
WHERE status = 'Active' AND brand_id = 1;

external_knowledge:
- 'forbidden fruit of excess sweetness' refers to desserts with a calorie count greater than 500 per 100g serving;
- 'discerning palates over the past year' signifies feedback provided in the last year;
- 'rankings stack up in the realm of indulgence' means ordering by average rating in descending order.

sql:
SELECT status, COUNT(dessert_id) AS number_of_desserts
FROM desserts
GROUP BY status;

SELECT d.name, b.brand_name, d.calories
FROM desserts d
JOIN brands b ON d.brand_id = b.brand_id;

SELECT name, AVG(calories) AS average_calories
FROM desserts
GROUP BY name;

SELECT name, calories 
FROM desserts 
WHERE calories = (SELECT MIN(calories) FROM desserts);

SELECT name, market_launch_date,
       DENSE_RANK() OVER (ORDER BY market_launch_date DESC) AS rank
FROM desserts;

SELECT name 
FROM desserts 
WHERE dessert_id = 1;
